28	pub fn is_builtin_excluded(path: &Path) -> bool {
29	    path.components().any(|c| {
30	        if let Component::Normal(name) = c {
31	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
32	        } else {
33	            false
34	        }
35	    })
36	}
