38	fn git_check_ignore(path: &Path) -> Option<bool> {
39	    let abs = path.canonicalize().ok()?;
40	    let parent = abs.parent()?;
41	    let output = Command::new("git")
42	        .args([
43	            "-C",
44	            &parent.to_string_lossy(),
45	            "check-ignore",
46	            "--",
47	            &abs.to_string_lossy(),
48	        ])
49	        .output()
50	        .ok()?;
51	    Some(output.status.code() == Some(0))
52	}
53	
54	pub fn is_git_ignored(path: &Path) -> bool {
55	    git_check_ignore(path).unwrap_or(false)
56	}
