58	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
59	    let mut builder = GlobSetBuilder::new();
60	    for pat in patterns {
61	        builder.add(Glob::new(pat)?);
62	    }
63	    builder.build()
64	}
