66	const EXT_LANG_MAP: &[(&str, Lang)] = &[
67	    ("rs", Lang::Rust),
68	    ("js", Lang::JavaScript),
69	    ("jsx", Lang::JavaScript),
70	    ("ts", Lang::TypeScript),
71	    ("tsx", Lang::Tsx),
72	    ("py", Lang::Python),
73	];
74	
75	pub fn detect_lang(path: &Path) -> Option<Lang> {
76	    let ext = path.extension().and_then(|e| e.to_str())?;
77	    EXT_LANG_MAP
78	        .iter()
79	        .find(|(e, _)| *e == ext)
80	        .map(|(_, l)| *l)
81	}
82	
83	pub fn is_rust_file(path: &Path) -> bool {
84	    path.extension().and_then(|e| e.to_str()) == Some("rs")
85	}
86	
87	pub fn is_supported_file(path: &Path) -> bool {
88	    detect_lang(path).is_some()
89	}
90	
91	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
92	    if exclude_set.is_empty() {
93	        return false;
94	    }
95	    exclude_set.is_match(path)
96	}
