98	/// Returns whether a file should be scanned.
99	/// When force_lang is Some, every non-excluded, non-builtin-excluded file is scanned.
100	/// When force_lang is None, only files with recognized extensions are scanned.
101	pub fn should_scan_file(
102	    path: &Path,
103	    exclude_set: &GlobSet,
104	    git_ignored: &dyn Fn(&Path) -> bool,
105	    force_lang: Option<Lang>,
106	) -> bool {
107	    if is_builtin_excluded(path) || should_skip(path, exclude_set) || git_ignored(path) {
108	        return false;
109	    }
110	    match force_lang {
111	        Some(_) => true,
112	        None => is_supported_file(path),
113	    }
114	}
