116	pub fn collect_all_functions(
117	    paths: &[String],
118	    exclude_set: &GlobSet,
119	    force_lang: Option<Lang>,
120	) -> (Vec<FunctionInfo>, Vec<String>) {
121	    let mut functions: Vec<FunctionInfo> = Vec::new();
122	    let mut errors: Vec<String> = Vec::new();
123	    for path_str in paths {
124	        let path = Path::new(path_str);
125	        if !path.exists() {
126	            errors.push(format!("path does not exist: {}", path_str));
127	        } else {
128	            collect_functions_from_path(path, exclude_set, force_lang, &mut functions, &mut errors);
129	        }
130	    }
131	    (functions, errors)
132	}
133	
134	pub fn collect_functions_from_path(
135	    path: &Path,
136	    exclude_set: &GlobSet,
137	    force_lang: Option<Lang>,
138	    functions: &mut Vec<FunctionInfo>,
139	    errors: &mut Vec<String>,
140	) {
141	    if path.is_file() {
142	        collect_from_single_file(path, exclude_set, force_lang, functions, errors);
143	    } else {
144	        collect_from_directory(path, exclude_set, force_lang, functions, errors);
145	    }
146	}
147	
148	pub fn collect_from_single_file(
149	    path: &Path,
150	    exclude_set: &GlobSet,
151	    force_lang: Option<Lang>,
152	    functions: &mut Vec<FunctionInfo>,
153	    errors: &mut Vec<String>,
154	) {
155	    if should_scan_file(path, exclude_set, &is_git_ignored, force_lang) {
156	        let lang = force_lang.or_else(|| detect_lang(path)).unwrap();
157	        process_file(path, lang, functions, errors);
158	    }
159	}
160	
161	fn process_entry(
162	    entry: Result<walkdir::DirEntry, walkdir::Error>,
163	    exclude_set: &GlobSet,
164	    force_lang: Option<Lang>,
165	    functions: &mut Vec<FunctionInfo>,
166	    errors: &mut Vec<String>,
167	) {
168	    match entry {
169	        Ok(e)
170	            if e.file_type().is_file()
171	                && should_scan_file(e.path(), exclude_set, &is_git_ignored, force_lang) =>
172	        {
173	            let lang = force_lang.or_else(|| detect_lang(e.path())).unwrap();
174	            process_file(e.path(), lang, functions, errors);
175	        }
176	        Ok(_) => {}
177	        Err(err) => errors.push(format!("walk error: {}", err)),
178	    }
179	}
180	
181	pub fn collect_from_directory(
182	    path: &Path,
183	    exclude_set: &GlobSet,
184	    force_lang: Option<Lang>,
185	    functions: &mut Vec<FunctionInfo>,
186	    errors: &mut Vec<String>,
187	) {
188	    let walker = WalkDir::new(path)
189	        .sort_by_file_name()
190	        .into_iter()
191	        .filter_entry(|e| {
192	            !e.file_type().is_dir() || (!is_builtin_excluded(e.path()) && !is_git_ignored(e.path()))
193	        });
194	    for entry in walker {
195	        process_entry(entry, exclude_set, force_lang, functions, errors);
196	    }
197	}
198	
199	pub fn process_file(
200	    path: &Path,
201	    lang: Lang,
202	    functions: &mut Vec<FunctionInfo>,
203	    errors: &mut Vec<String>,
204	) {
205	    let source = match std::fs::read_to_string(path) {
206	        Ok(s) => s,
207	        Err(e) => {
208	            errors.push(format!("cannot read {}: {}", path.display(), e));
209	            return;
210	        }
211	    };
212	
213	    let config: &LangConfig = lang_config(lang);
214	    match parse_source_tree_for(&source, lang) {
215	        Ok(tree) => {
216	            let file_str = path.to_string_lossy().to_string();
217	            extract_functions_with_config(tree.root_node(), &source, &file_str, config, functions);
218	        }
219	        Err(msg) => {
220	            errors.push(format!("{} in {}", msg, path.display()));
221	        }
222	    }
223	}
